.step-indicator {
    padding: 1rem 0;
}

.step-item {
    position: relative;
    cursor: default;
}

.step-item.completed {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    border: 2px solid #dee2e6;
    background: #fff;
    transition: all 0.2s;
}

.step-item.active .step-circle {
    border-color: var(--bs-primary);
    transform: scale(1.1);
}

.step-item.completed .step-circle {
    border-color: var(--bs-success);
}

.step-item.dimmed .step-circle {
    opacity: 0.5;
}

.step-label {
    font-size: 0.75rem;
    display: block;
    margin-top: 0.25rem;
}

