{"file_text": "<nav class="step-indicator mb-4">
    <div class="d-flex justify-content-between position-relative">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var isCompleted = step < CurrentStep;
            var isCurrent = step == CurrentStep;
            var isFuture = step > CurrentStep;

            <div class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "dimmed" : "")"
                 role="button"
                 @onclick="() => HandleStepClick(step)">
                <div class="step-circle mx-auto mb-1 @(isCurrent ? "bg-primary text-white" : "") @(isCompleted ? "bg-success text-white" : "")">
                    @if (isCompleted)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@(step + 1)</span>
