@using sv_9f4816a63fd648b393836c09a4f8d241.Models

<h4 class="mb-4">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.FullName" placeholder="John Doe" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" @bind="Model.Email" placeholder="john@example.com" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" @bind="Model.Phone" placeholder="(555) 123-4567" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" @bind="Model.Address" placeholder="123 Main St, City, State" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next →</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Model.FullName))
        { ErrorMessage = "Full name is required."; return; }

        if (string.IsNullOrWhiteSpace(Model.Email))
        { ErrorMessage = "Email is required."; return; }

        if (string.IsNullOrWhiteSpace(Model.Phone))
        { ErrorMessage = "Phone number is required."; return; }

        if (string.IsNullOrWhiteSpace(Model.Address))
        { ErrorMessage = "Address is required."; return; }

        if (ValidateEmail is not null)
        {
            IsValidating = true;
            StateHasChanged();

            var isValid = await ValidateEmail(Model.Email);
            IsValidating = false;

            if (!isValid)
            { ErrorMessage = "Please enter a valid email address."; return; }
        }

        await OnNext.InvokeAsync();
    }
}

